/**
 * TunnelVision Bridge
 * Deep integration between Nemo's Guides and TunnelVision.
 * Provides functions to read TV's state and share NG's context back.
 *
 * Synergies:
 *   1. Scene context → TV search hints (NG's assessment helps TV retrieve better)
 *   2. DM Notes → TV search context (plot threads inform lorebook navigation)
 *   3. Writing analyzer → TV output quality (slop scan on TV-generated content)
 *   4. Tracker awareness (avoid duplicate trackers between NG and TV)
 *   5. TV lorebook context → NG Rule Setup (richer world context for rules)
 */

const LOG_PREFIX = '[NemosGuides:TVBridge]';

/** Cached TV module references — loaded lazily to avoid hard dependency. */
let tvModules = null;

/**
 * Lazily import TunnelVision modules.
 * Returns null if TV is not installed.
 * @returns {Promise<object|null>}
 */
async function getTVModules() {
    if (tvModules) return tvModules;

    try {
        const [toolRegistry, treeStore] = await Promise.all([
            import('../../../TunnelVision/tool-registry.js'),
            import('../../../TunnelVision/tree-store.js'),
        ]);

        tvModules = { toolRegistry, treeStore };
        console.log(`${LOG_PREFIX} TunnelVision modules loaded.`);
        return tvModules;
    } catch {
        // TV not installed or modules not found
        console.log(`${LOG_PREFIX} TunnelVision not available — bridge disabled.`);
        return null;
    }
}

/**
 * Check if TunnelVision is available.
 * @returns {Promise<boolean>}
 */
export async function isTVAvailable() {
    return !!(await getTVModules());
}

// ── Synergy 1: Share scene context with TV ──

/**
 * Get a scene context summary that TV's search can use as hints.
 * Pulls from NG's latest scene assessment data.
 * @returns {Promise<string>} Scene context string for TV
 */
export async function getSceneContextForTV() {
    try {
        const { getContext } = await import('../../../../../extensions.js');
        const context = getContext();

        // Read NG's latest scene data from chat variables
        const vars = ['ng_last_situation', 'ng_last_thinking', 'ng_last_clothing', 'ng_last_positions'];
        const parts = [];

        for (const varName of vars) {
            try {
                const result = await context.executeSlashCommandsWithOptions(`/getvar ${varName}`, {
                    showOutput: false,
                    handleExecutionErrors: true,
                });
                const val = result?.pipe?.trim();
                if (val && val.length > 10) {
                    const label = varName.replace('ng_last_', '');
                    parts.push(`[NG ${label}]: ${val.substring(0, 300)}`);
                }
            } catch { /* variable doesn't exist yet */ }
        }

        return parts.length > 0 ? parts.join('\n') : '';
    } catch {
        return '';
    }
}

// ── Synergy 2: DM Notes inform TV search ──

/**
 * Get plot-relevant search hints from NG's DM Notes.
 * Returns key terms and names from active plot threads and off-screen events.
 * @returns {Promise<string>}
 */
export async function getDMNotesSearchHints() {
    try {
        const { getTrackerContent } = await import('./lorebook-manager.js');
        const notes = await getTrackerContent('dm_notes');
        if (!notes || notes.length < 20) return '';

        // Extract key terms from plot threads and off-screen sections
        const plotMatch = notes.match(/♢ Plot Threads\n([\s\S]*?)(?=♢ |$)/);
        const offscreenMatch = notes.match(/♢ Off-Screen Events\n([\s\S]*?)(?=♢ |$)/);

        const hints = [];
        if (plotMatch?.[1]?.trim()) hints.push(`Active plots: ${plotMatch[1].trim().substring(0, 200)}`);
        if (offscreenMatch?.[1]?.trim()) hints.push(`Off-screen: ${offscreenMatch[1].trim().substring(0, 200)}`);

        return hints.join('\n');
    } catch {
        return '';
    }
}

// ── Synergy 3: Writing analyzer scans TV output ──

/**
 * Scan TV-generated content (summaries, remembered entries) for slop patterns.
 * @param {string} tvOutput - Text generated by TV's sidecar
 * @returns {Array} Slop scan results
 */
export async function scanTVOutputForSlop(tvOutput) {
    if (!tvOutput) return [];

    try {
        const { scanForSlop } = await import('./slop-patterns.js');
        return scanForSlop(tvOutput);
    } catch {
        return [];
    }
}

// ── Synergy 4: Tracker awareness ──

/**
 * Get TV's tracked entry names to avoid duplicate tracking.
 * @returns {Promise<string[]>} List of TV tracker entry names
 */
export async function getTVTrackerNames() {
    const tv = await getTVModules();
    if (!tv) return [];

    try {
        const trackerList = tv.toolRegistry.getTrackerListString();
        if (!trackerList) return [];

        // Parse the tracker list string into individual names
        return trackerList
            .replace(/^.*?:\s*/, '') // Remove "Tracked entries: " prefix
            .split(',')
            .map(s => s.trim())
            .filter(Boolean);
    } catch {
        return [];
    }
}

/**
 * Check if TV is already tracking something that NG would also track.
 * Returns overlap information.
 * @returns {Promise<{ overlapping: string[], tvOnly: string[], ngOnly: string[] }>}
 */
export async function getTrackerOverlap() {
    const tvTrackers = await getTVTrackerNames();
    const ngTrackers = ['clothing', 'positions', 'situation', 'thinking', 'rules', 'narrator', 'dm_notes'];

    // Simple keyword matching for overlap detection
    const clothingKeywords = ['clothing', 'clothes', 'outfit', 'appearance', 'wearing'];
    const positionKeywords = ['position', 'state', 'location', 'physical'];
    const moodKeywords = ['mood', 'emotion', 'feeling', 'mental', 'thinking'];

    const overlapping = [];
    const tvLower = tvTrackers.map(t => t.toLowerCase());

    if (tvLower.some(t => clothingKeywords.some(k => t.includes(k)))) {
        overlapping.push('clothing/appearance');
    }
    if (tvLower.some(t => positionKeywords.some(k => t.includes(k)))) {
        overlapping.push('positions/physical state');
    }
    if (tvLower.some(t => moodKeywords.some(k => t.includes(k)))) {
        overlapping.push('mood/thinking');
    }

    return {
        overlapping,
        tvOnly: tvTrackers.filter(t => !overlapping.some(o => t.toLowerCase().includes(o.split('/')[0]))),
        ngOnly: ngTrackers,
    };
}

// ── Synergy 5: TV lorebook context for Rule Setup ──

/**
 * Get rich world context from TV's lorebook tree for NG's Rule Setup.
 * Reads TV's tree structure and book descriptions.
 * @returns {Promise<string>} World context from TV's lorebooks
 */
export async function getTVWorldContext() {
    const tv = await getTVModules();
    if (!tv) return '';

    try {
        const activeBooks = tv.toolRegistry.getReadableBooks();
        if (!activeBooks?.length) return '';

        const parts = [];

        for (const bookName of activeBooks) {
            const tree = tv.treeStore.getTree(bookName);
            if (!tree?.root) continue;

            const desc = tv.treeStore.getBookDescription(bookName);
            const treeOverview = tv.treeStore.buildTreeDescription(tree.root, 0);

            parts.push(`## Lorebook: ${bookName}`);
            if (desc) parts.push(`Description: ${desc}`);
            if (treeOverview) parts.push(`Structure:\n${treeOverview.substring(0, 500)}`);
        }

        if (parts.length === 0) return '';

        return `\n## TunnelVision World Data\n${parts.join('\n\n')}`;
    } catch (error) {
        console.warn(`${LOG_PREFIX} Could not read TV world context:`, error);
        return '';
    }
}

/**
 * Get a summary of the TV + NG integration status.
 * Used by the NG tab in TV's panel.
 * @returns {Promise<object>}
 */
export async function getIntegrationStatus() {
    const tv = await getTVModules();
    if (!tv) {
        return { available: false };
    }

    try {
        const activeBooks = tv.toolRegistry.getReadableBooks();
        const trackerOverlap = await getTrackerOverlap();

        return {
            available: true,
            activeBooks: activeBooks || [],
            trackerOverlap,
            tvTrackers: await getTVTrackerNames(),
        };
    } catch {
        return { available: true, error: 'Could not read TV state' };
    }
}
